+
+        // with_overrides_from uses current_capabilities_with_base
+        let caps = base.with_overrides_from(base);
+        assert!(caps.true_color);
+        assert!(!caps.colors_256); // base dumb
+
+        clear_all_overrides();
+    }
+
+    #[test]
