+    // ── clear_all then push resumes ───────────────────────────────────
+
+    #[test]
+    fn clear_all_then_push_resumes_normally() {
+        clear_all_overrides();
+
+        let _g1 = push_override(CapabilityOverride::dumb());
+        clear_all_overrides();
+        assert_eq!(override_depth(), 0);
+
