+
+    #[test]
+    fn current_capabilities_uses_detect_as_base() {
+        clear_all_overrides();
+
+        // Force a known state via dumb override
+        let _g = push_override(CapabilityOverride::dumb());
+        let caps = current_capabilities();
+        assert!(!caps.true_color);
+        assert!(!caps.mouse_sgr);
